package com.example.mfa.service;

import com.example.mfa.domain.AppUser;
import com.example.mfa.domain.BackupCode;
import com.example.mfa.repository.AppUserRepository;
import com.example.mfa.repository.BackupCodeRepository;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.security.SecureRandom;
import java.time.Instant;
import java.util.ArrayList;
import java.util.Base64;
import java.util.List;
import java.util.Locale;
import java.util.UUID;

@Service
public class MfaBackupCodeService {
    private final AppUserRepository appUserRepository;
    private final BackupCodeRepository backupCodeRepository;
    private final PasswordEncoder passwordEncoder;
    private final SecureRandom secureRandom = new SecureRandom();

    @Value("${mfa.backup-code.count:10}")
    private int backupCodeCount;

    public MfaBackupCodeService(AppUserRepository appUserRepository,
                                BackupCodeRepository backupCodeRepository,
                                PasswordEncoder passwordEncoder) {
        this.appUserRepository = appUserRepository;
        this.backupCodeRepository = backupCodeRepository;
        this.passwordEncoder = passwordEncoder;
    }

    @Transactional
    public List<String> enableMfaAndGenerateBackupCodes(UUID userId, String totpSecret) {
        AppUser user = appUserRepository.findById(userId)
                .orElseThrow(() -> new IllegalArgumentException("User not found"));
        user.setMfaEnabled(true);
        user.setTotpSecret(totpSecret);
        backupCodeRepository.findByUserIdAndUsedFalse(userId).forEach(backupCodeRepository::delete);
        List<String> rawCodes = generateBackupCodes(backupCodeCount);
        for (String raw : rawCodes) {
            BackupCode code = new BackupCode();
            code.setUser(user);
            code.setCodeHash(passwordEncoder.encode(raw));
            code.setUsed(false);
            code.setUsedAt(null);
            backupCodeRepository.save(code);
        }
        appUserRepository.save(user);
        return rawCodes;
    }

    @Transactional
    public boolean authenticateWithBackupCode(String username, String rawBackupCode) {
        AppUser user = appUserRepository.findByUsername(username)
                .orElseThrow(() -> new IllegalArgumentException("User not found"));
        if (!user.isMfaEnabled()) {
            return false;
        }
        List<BackupCode> codes = backupCodeRepository.findByUserIdAndUsedFalse(user.getId());
        for (BackupCode code : codes) {
            if (passwordEncoder.matches(rawBackupCode, code.getCodeHash())) {
                code.setUsed(true);
                code.setUsedAt(Instant.now());
                backupCodeRepository.save(code);
                return true;
            }
        }
        return false;
    }

    @Transactional(readOnly = true)
    public List<String> listRemainingBackupCodes(UUID userId) {
        long count = backupCodeRepository.countByUserIdAndUsedFalse(userId);
        List<String> result = new ArrayList<>();
        for (int i = 0; i < count; i++) {
            result.add("REDACTED");
        }
        return result;
    }

    @Transactional
    public List<String> regenerateBackupCodes(UUID userId) {
        AppUser user = appUserRepository.findById(userId)
                .orElseThrow(() -> new IllegalArgumentException("User not found"));
        backupCodeRepository.findByUserIdAndUsedFalse(userId).forEach(backupCodeRepository::delete);
        List<String> rawCodes = generateBackupCodes(backupCodeCount);
        for (String raw : rawCodes) {
            BackupCode code = new BackupCode();
            code.setUser(user);
            code.setCodeHash(passwordEncoder.encode(raw));
            code.setUsed(false);
            backupCodeRepository.save(code);
        }
        return rawCodes;
    }

    private List<String> generateBackupCodes(int count) {
        List<String> codes = new ArrayList<>(count);
        for (int i = 0; i < count; i++) {
            codes.add(formatCode(generateCodeBytes()));
        }
        return codes;
    }

    private byte[] generateCodeBytes() {
        byte[] bytes = new byte[10];
        secureRandom.nextBytes(bytes);
        return bytes;
    }

    private String formatCode(byte[] bytes) {
        String encoded = Base64.getUrlEncoder().withoutPadding().encodeToString(bytes).toUpperCase(Locale.ROOT);
        if (encoded.length() < 16) {
            encoded = encoded + "X".repeat(16 - encoded.length());
        }
        return encoded.substring(0, 16);
    }
}

package com.example.mfa.web;

import com.example.mfa.service.MfaBackupCodeService;
import jakarta.validation.constraints.NotBlank;
import jakarta.validation.constraints.NotNull;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

import java.util.List;
import java.util.UUID;

@RestController
@RequestMapping("/api/mfa")
class MfaController {
    private final MfaBackupCodeService mfaBackupCodeService;

    public MfaController(MfaBackupCodeService mfaBackupCodeService) {
        this.mfaBackupCodeService = mfaBackupCodeService;
    }

    @PostMapping("/enable")
    public ResponseEntity<EnableMfaResponse> enable(@RequestBody EnableMfaRequest request) {
        List<String> backupCodes = mfaBackupCodeService.enableMfaAndGenerateBackupCodes(request.userId, request.totpSecret);
        return ResponseEntity.ok(new EnableMfaResponse(true, backupCodes));
    }

    @PostMapping("/backup-auth")
    public ResponseEntity<BackupAuthResponse> backupAuth(@RequestBody BackupAuthRequest request) {
        boolean authenticated = mfaBackupCodeService.authenticateWithBackupCode(request.username, request.backupCode);
        return ResponseEntity.ok(new BackupAuthResponse(authenticated));
    }

    @PostMapping("/backup-codes/regenerate")
    public ResponseEntity<RegenerateBackupCodesResponse> regenerate(@RequestBody RegenerateBackupCodesRequest request) {
        List<String> backupCodes = mfaBackupCodeService.regenerateBackupCodes(request.userId);
        return ResponseEntity.ok(new RegenerateBackupCodesResponse(backupCodes));
    }

    public record EnableMfaRequest(@NotNull UUID userId, @NotBlank String totpSecret) {}
    public record EnableMfaResponse(boolean mfaEnabled, List<String> backupCodes) {}
    public record BackupAuthRequest(@NotBlank String username, @NotBlank String backupCode) {}
    public record BackupAuthResponse(boolean authenticated) {}
    public record RegenerateBackupCodesRequest(@NotNull UUID userId) {}
    public record RegenerateBackupCodesResponse(List<String> backupCodes) {}
}

